extern "C" {
    // Opaque types from ROUP
    struct OmpDirective;
    struct OmpClause;
    struct OmpClauseIterator;

    // Core parsing
    OmpDirective* roup_parse(const char* input);
    OmpDirective* roup_parse_with_language(const char* input, int32_t language);
    void roup_directive_free(OmpDirective* directive);

    // Directive queries
    int32_t roup_directive_kind(const OmpDirective* directive);
    const char* roup_directive_name(const OmpDirective* directive);
    int32_t roup_directive_clause_count(const OmpDirective* directive);
    OmpClauseIterator* roup_directive_clauses_iter(const OmpDirective* directive);

    // Iterator operations (updated API with out parameter)
    int32_t roup_clause_iterator_next(OmpClauseIterator* iter, const OmpClause** out);
    void roup_clause_iterator_free(OmpClauseIterator* iter);

    // Clause queries
    int32_t roup_clause_kind(const OmpClause* clause);
    const char* roup_clause_arguments(const OmpClause* clause);

    // Specialized clause data
    int32_t roup_clause_schedule_kind(const OmpClause* clause);
    int32_t roup_clause_reduction_operator(const OmpClause* clause);
    int32_t roup_clause_default_data_sharing(const OmpClause* clause);
}

// ============================================================================
// Global State
// ============================================================================

static OpenMPBaseLang current_lang = Lang_C;

// Language prefix constants - defined once to avoid manual synchronization
static constexpr const char FORTRAN_PREFIX[] = "!$omp";       // Fortran prefix (lowercase)
static constexpr const char FORTRAN_PREFIX_UPPER[] = "!$OMP"; // Fortran prefix (uppercase)
static constexpr const char C_PRAGMA_PREFIX[] = "#pragma";    // C/C++ pragma prefix
// Compile-time string lengths: sizeof() includes null terminator, subtract 1 for actual length
static constexpr size_t FORTRAN_PREFIX_LEN = sizeof(FORTRAN_PREFIX) - 1;
static constexpr size_t C_PRAGMA_PREFIX_LEN = sizeof(C_PRAGMA_PREFIX) - 1;

// setLang uses C++ linkage (not extern "C") to match ompparser's original implementation
void setLang(OpenMPBaseLang lang) {
    current_lang = lang;
}

// ============================================================================
// Helper Functions
// ============================================================================

static OpenMPDirectiveKind mapRoupToOmpparserDirective(int32_t roup_kind) {
    // ROUP directive kind codes now match ompparser enum values exactly
    // (see c_api.rs:directive_name_to_kind() for complete mapping)
    // We can pass through the value directly, just cast to the enum type
    if (roup_kind >= 0 && roup_kind < 86) {
        return static_cast<OpenMPDirectiveKind>(roup_kind);
    }
    return OMPD_unknown;
}

static OpenMPClauseKind mapRoupToOmpparserClause(int32_t roup_kind) {
    // ROUP clause kind codes now match ompparser enum values exactly
    // (see c_api.rs:convert_clause() for complete mapping)
    // We can pass through the value directly, just cast to the enum type
    if (roup_kind >= 0 && roup_kind < 89) {
        return static_cast<OpenMPClauseKind>(roup_kind);
    }
    return OMPC_unknown;
}

// Fix spacing for linear/aligned modifiers: val(a,b,c):2 -> val( a, b, c) :2
// Adds space after opening paren, before closing paren, after commas, and before colon
static std::string fixLinearAlignedModifierSpacing(const std::string& arg) {
    std::string result;
    int paren_depth = 0;
    bool in_modifier = false;  // Track if we're inside modifier parens like val()

    for (size_t i = 0; i < arg.length(); ++i) {
        char c = arg[i];

        if (c == '(') {
            result += c;
            paren_depth++;
            if (paren_depth == 1) {
                in_modifier = true;
                // Add space after opening paren
                if (i + 1 < arg.length() && arg[i + 1] != ' ') {
                    result += ' ';
                }
            }
        } else if (c == ')') {
            // NO space before closing paren - commas already added spaces
            result += c;
            paren_depth--;
            if (paren_depth == 0) {
                in_modifier = false;
                // Add space before colon: ) :2
                if (i + 1 < arg.length() && arg[i + 1] == ':') {
                    result += ' ';
                }
            }
        } else if (c == ',' && in_modifier && paren_depth == 1) {
            // Add comma and space after it inside modifier
            result += c;
            if (i + 1 < arg.length() && arg[i + 1] != ' ') {
                result += ' ';
            }
        } else {
            result += c;
        }
    }
    return result;
}

// Fix spacing in clause arguments: add space after colons if not present
// "conditional:a" -> "conditional: a", "allocator:x" -> "allocator: x"
// BUT NOT inside array sections: keep "a[1:10]" as-is
static std::string fixClauseArgumentSpacing(const std::string& arg) {
    std::string result;
    int bracket_depth = 0;  // Track if we're inside []
    for (size_t i = 0; i < arg.length(); ++i) {
        char c = arg[i];
        result += c;

        if (c == '[') bracket_depth++;
        else if (c == ']') bracket_depth--;
        // Add space after colon ONLY if:
        // - Not inside brackets (array sections)
        // - Next char is not already a space
        // - Not at end of string
        else if (c == ':' && bracket_depth == 0 &&
                 i + 1 < arg.length() && arg[i + 1] != ' ' && arg[i + 1] != '\t') {
            result += ' ';
        }
    }
    return result;
}

// Parse and split clause arguments by commas, respecting nesting
// Handles: a, b, c[1:10], foo(x, y), bar[baz(a, b):20]
static std::vector<std::string> parseClauseArguments(const char* args) {
    std::vector<std::string> result;
    if (!args || args[0] == '\0') {
        return result;
    }

    std::string current;
    int paren_depth = 0;
    int bracket_depth = 0;

    for (const char* p = args; *p; ++p) {
        char c = *p;

        if (c == '(') {
            paren_depth++;
            current += c;
        } else if (c == ')') {
            paren_depth--;
            current += c;
        } else if (c == '[') {
            bracket_depth++;
            current += c;
        } else if (c == ']') {
            bracket_depth--;
            current += c;
        } else if (c == ',' && paren_depth == 0 && bracket_depth == 0) {
            // Top-level comma - split here
            // Trim whitespace
            size_t start = current.find_first_not_of(" \t");
            size_t end = current.find_last_not_of(" \t");
            if (start != std::string::npos) {
                result.push_back(current.substr(start, end - start + 1));
            }
            current.clear();
        } else {
            current += c;
        }
    }

    // Don't forget the last part
    size_t start = current.find_first_not_of(" \t");
    size_t end = current.find_last_not_of(" \t");
    if (start != std::string::npos) {
        result.push_back(current.substr(start, end - start + 1));
    }

    return result;
}

// Parse schedule clause arguments: modifier1,modifier2:kind,chunk
// Returns: {modifiers, kind, chunk}
struct ScheduleInfo {
    OpenMPScheduleClauseModifier modifier1;
    OpenMPScheduleClauseModifier modifier2;
    OpenMPScheduleClauseKind kind;
    std::string chunk;
};

static ScheduleInfo parseScheduleArguments(const char* args) {
    ScheduleInfo info;
    info.modifier1 = OMPC_SCHEDULE_MODIFIER_unknown;
    info.modifier2 = OMPC_SCHEDULE_MODIFIER_unknown;
    info.kind = OMPC_SCHEDULE_KIND_unspecified;
    info.chunk = "";

    if (!args || args[0] == '\0') {
        return info;
    }

    std::string args_str(args);

    // Split by colon to separate modifiers from kind/chunk
    size_t colon_pos = args_str.find(':');
    std::string modifiers_str = (colon_pos != std::string::npos) ? args_str.substr(0, colon_pos) : "";
    std::string kind_chunk_str = (colon_pos != std::string::npos) ? args_str.substr(colon_pos + 1) : args_str;

    // Parse modifiers (comma-separated before colon)
    if (!modifiers_str.empty()) {
        std::vector<std::string> modifiers = parseClauseArguments(modifiers_str.c_str());
        for (size_t i = 0; i < modifiers.size() && i < 2; ++i) {
            std::string mod_lower = modifiers[i];
            std::transform(mod_lower.begin(), mod_lower.end(), mod_lower.begin(), ::tolower);

            OpenMPScheduleClauseModifier mod = OMPC_SCHEDULE_MODIFIER_unknown;
            if (mod_lower == "monotonic") mod = OMPC_SCHEDULE_MODIFIER_monotonic;
            else if (mod_lower == "nonmonotonic") mod = OMPC_SCHEDULE_MODIFIER_nonmonotonic;
            else if (mod_lower == "simd") mod = OMPC_SCHEDULE_MODIFIER_simd;

            if (i == 0) info.modifier1 = mod;
            else info.modifier2 = mod;
        }
    }

    // Parse kind and chunk (comma-separated after colon)
    if (!kind_chunk_str.empty()) {
        std::vector<std::string> parts = parseClauseArguments(kind_chunk_str.c_str());
        if (!parts.empty()) {
            std::string kind_lower = parts[0];
            std::transform(kind_lower.begin(), kind_lower.end(), kind_lower.begin(), ::tolower);

            if (kind_lower == "static") info.kind = OMPC_SCHEDULE_KIND_static;
            else if (kind_lower == "dynamic") info.kind = OMPC_SCHEDULE_KIND_dynamic;
            else if (kind_lower == "guided") info.kind = OMPC_SCHEDULE_KIND_guided;
            else if (kind_lower == "auto") info.kind = OMPC_SCHEDULE_KIND_auto;
            else if (kind_lower == "runtime") info.kind = OMPC_SCHEDULE_KIND_runtime;

            if (parts.size() > 1) {
                info.chunk = parts[1];
            }
        }
    }

    return info;
}

// ============================================================================
// Main Entry Point - ROUP-BASED PARSER
// ============================================================================

extern "C" {

OpenMPDirective* parseOpenMP(const char* input, void* exprParse(const char* expr)) {
    if (!input || input[0] == '\0') {
        return nullptr;
    }

    // Validate input length using constant from ROUP C API
    // Use strnlen to safely handle potentially untrusted/non-null-terminated input
    const size_t input_len = strnlen(input, ROUP_MAX_PRAGMA_LENGTH);
    if (input_len == ROUP_MAX_PRAGMA_LENGTH) {
        return nullptr;  // Input too long or not null-terminated within limit
    }

    // Determine input format based on current language mode
    std::string input_str(input, input_len);

    // Handle different language pragmas
    if (current_lang == Lang_Fortran) {
        // Fortran uses !$omp prefix - add if missing (case-insensitive check)
        const bool has_prefix =
            input_str.length() >= FORTRAN_PREFIX_LEN &&
            (input_str.compare(0, FORTRAN_PREFIX_LEN, FORTRAN_PREFIX) == 0 ||
             input_str.compare(0, FORTRAN_PREFIX_LEN, FORTRAN_PREFIX_UPPER) == 0);
        if (!has_prefix) {
            input_str = std::string(FORTRAN_PREFIX) + " " + input_str;
        }
    } else {
        // C/C++ use #pragma omp prefix - add if missing
        // compare() returns 0 if strings match, non-zero otherwise
        if (input_str.compare(0, C_PRAGMA_PREFIX_LEN, C_PRAGMA_PREFIX) != 0) {
            input_str = std::string(C_PRAGMA_PREFIX) + " " + input_str;
        }
    }

    // WORKAROUND: ROUP cannot parse "cancellation point" directive at all
    // Detect and handle manually
    std::string search_lower = input_str;
    std::transform(search_lower.begin(), search_lower.end(), search_lower.begin(), ::tolower);
    if (search_lower.find("cancellation") != std::string::npos && search_lower.find("point") != std::string::npos) {
        // This is a "cancellation point" directive
        OpenMPDirective* dir = new OpenMPDirective(OMPD_cancellation_point, current_lang, 0, 0);

        // Extract construct type (parallel/sections/for/do/taskgroup)
        size_t point_pos = search_lower.find("point");
        if (point_pos != std::string::npos) {
            std::string after = search_lower.substr(point_pos + 5); // skip "point"
            size_t start = after.find_first_not_of(" \t");
            if (start != std::string::npos) {
                std::string first_token = after.substr(start);
                size_t end = first_token.find_first_of(" \t\r\n");
                if (end != std::string::npos) {
                    first_token = first_token.substr(0, end);
                }

                if (first_token == "parallel") {
                    dir->addOpenMPClause(OMPC_parallel);
                } else if (first_token == "sections") {
                    dir->addOpenMPClause(OMPC_sections);
                } else if (first_token == "for" || first_token == "do") {
                    dir->addOpenMPClause(current_lang == Lang_Fortran ? OMPC_do : OMPC_for);
                } else if (first_token == "taskgroup") {
                    dir->addOpenMPClause(OMPC_taskgroup);
                }
            }
        }

        return dir;
    }

    // WORKAROUND: ROUP cannot parse Fortran "end X" directives (end do, end simd, etc.)
    // Only match if "end " appears right after the !$omp prefix
    size_t omp_end_pos = search_lower.find("!$omp end ");
    if (current_lang == Lang_Fortran && omp_end_pos != std::string::npos) {
        // Extract the paired directive name (e.g., "do", "simd", "sections")
        size_t end_pos = omp_end_pos + 6; // position of "end "
        std::string after = search_lower.substr(end_pos + 4); // skip "end "
        size_t start = after.find_first_not_of(" \t");
        std::string paired_name;
        if (start != std::string::npos) {
            std::string token = after.substr(start);
            size_t end = token.find_first_of(" \t\r\n");
            if (end != std::string::npos) {
                paired_name = token.substr(0, end);
            } else {
                paired_name = token;
            }
        }

        // Create a minimal paired directive that will output the correct name
        // Map common paired names to directive kinds
        OpenMPDirectiveKind paired_kind = OMPD_unknown;
        if (paired_name == "do") paired_kind = OMPD_do;
        else if (paired_name == "simd") paired_kind = OMPD_simd;
        else if (paired_name == "atomic") paired_kind = OMPD_atomic;
        else if (paired_name == "critical") paired_kind = OMPD_critical;
        else if (paired_name == "sections") paired_kind = OMPD_sections;
        else if (paired_name == "single") paired_kind = OMPD_single;
        else if (paired_name == "parallel") paired_kind = OMPD_parallel;
        else if (paired_name == "ordered") paired_kind = OMPD_ordered;
        else if (paired_name == "loop") paired_kind = OMPD_loop;
        else if (paired_name == "distribute") paired_kind = OMPD_distribute;
        else if (paired_name.find("do simd") != std::string::npos) paired_kind = OMPD_do_simd;
        else if (paired_name.find("distribute parallel do simd") != std::string::npos) paired_kind = OMPD_distribute_parallel_do_simd;
        else if (paired_name.find("distribute parallel do") != std::string::npos) paired_kind = OMPD_distribute_parallel_do;

        // Only create end directive if we have a valid paired directive
        if (paired_kind != OMPD_unknown) {
            OpenMPEndDirective* end_dir = new OpenMPEndDirective();
            end_dir->setBaseLang(current_lang);
            OpenMPDirective* paired = new OpenMPDirective(paired_kind, current_lang, 0, 0);
            end_dir->setPairedDirective(paired);
            return end_dir;
        }
        // If we can't determine the paired directive, fall through to ROUP parser
    }

    // Call ROUP parser with language awareness - THIS IS THE REAL PARSER!
    // Map ompparser language to ROUP language constants
    int32_t roup_lang = (current_lang == Lang_Fortran) ? ROUP_LANG_FORTRAN_FREE : ROUP_LANG_C;

    OmpDirective* roup_dir = roup_parse_with_language(input_str.c_str(), roup_lang);
    if (!roup_dir) {
        return nullptr;
    }

    // Get directive kind and name from ROUP
    int32_t roup_kind = roup_directive_kind(roup_dir);
    const char* roup_name = roup_directive_name(roup_dir);
    OpenMPDirectiveKind kind = mapRoupToOmpparserDirective(roup_kind);

    // Create ompparser-compatible directive
    // Use OpenMPAtomicDirective for atomic directives
    OpenMPDirective* dir = nullptr;
    if (kind == OMPD_atomic) {
        OpenMPAtomicDirective* atomic_dir = new OpenMPAtomicDirective();
        atomic_dir->setBaseLang(current_lang);
        dir = atomic_dir;

        // Add atomic operation clause if present (read/write/update/capture)
        std::string name_str(roup_name);
        if (name_str.find("read") != std::string::npos) {
            atomic_dir->addOpenMPClause(OMPC_read);
        } else if (name_str.find("write") != std::string::npos) {
            atomic_dir->addOpenMPClause(OMPC_write);
        } else if (name_str.find("capture") != std::string::npos) {
            atomic_dir->addOpenMPClause(OMPC_capture);
        } else if (name_str.find("update") != std::string::npos) {
            atomic_dir->addOpenMPClause(OMPC_update);
        }
    } else {
        dir = new OpenMPDirective(kind, current_lang, 0, 0);

        // WORKAROUND: ROUP parser bug - cancel/cancellation_point don't parse construct type
        // Manually extract construct type from input and add as clause
        if (kind == OMPD_cancel || kind == OMPD_cancellation_point) {
            // Parse construct type from input: parallel, sections, for/do, taskgroup
            std::string search_str = input_str;
            size_t pos = search_str.find(roup_name);
            if (pos != std::string::npos) {
                std::string after = search_str.substr(pos + strlen(roup_name));
                // Skip whitespace
                size_t start = after.find_first_not_of(" \t");
                if (start != std::string::npos) {
                    std::string first_token = after.substr(start);
                    size_t end = first_token.find_first_of(" \t(");
                    if (end != std::string::npos) {
                        first_token = first_token.substr(0, end);
                    }
                    // Convert to lowercase for comparison
                    std::transform(first_token.begin(), first_token.end(), first_token.begin(), ::tolower);

                    if (first_token == "parallel") {
                        dir->addOpenMPClause(OMPC_parallel);
                    } else if (first_token == "sections") {
                        dir->addOpenMPClause(OMPC_sections);
                    } else if (first_token == "for" || first_token == "do") {
                        dir->addOpenMPClause(current_lang == Lang_Fortran ? OMPC_do : OMPC_for);
                    } else if (first_token == "taskgroup") {
                        dir->addOpenMPClause(OMPC_taskgroup);
                    }
                }
            }
        }
    }

    // Convert clauses using ompparser's addOpenMPClause method
    OmpClauseIterator* iter = roup_directive_clauses_iter(roup_dir);
    if (iter) {
        const OmpClause* roup_clause;
        while (roup_clause_iterator_next(iter, &roup_clause) == 1) {
            int32_t roup_kind_clause = roup_clause_kind(roup_clause);
            OpenMPClauseKind clause_kind = mapRoupToOmpparserClause(roup_kind_clause);

            OpenMPClause* omp_clause = nullptr;
            bool skip_std_args = false;  // Flag to skip standard argument processing

            // Handle specialized clauses that need parameters
            if (clause_kind == OMPC_default) {
                // Default clause needs default kind parameter
                int32_t roup_default = roup_clause_default_data_sharing(roup_clause);
                // Map ROUP values (0=shared, 1=none) to ompparser enum
                // OMPC_DEFAULT_shared=2, OMPC_DEFAULT_none=3
                OpenMPDefaultClauseKind default_kind =
                    (roup_default == 0) ? OMPC_DEFAULT_shared :
                    (roup_default == 1) ? OMPC_DEFAULT_none :
                    OMPC_DEFAULT_unknown;
                omp_clause = dir->addOpenMPClause(static_cast<int>(clause_kind), static_cast<int>(default_kind));
                skip_std_args = true;
            } else if (clause_kind == OMPC_schedule) {
                // Schedule clause needs modifier1, modifier2, and kind
                const char* args = roup_clause_arguments(roup_clause);
                ScheduleInfo sched_info = parseScheduleArguments(args);
                omp_clause = dir->addOpenMPClause(static_cast<int>(clause_kind),
                    static_cast<int>(sched_info.modifier1),
                    static_cast<int>(sched_info.modifier2),
                    static_cast<int>(sched_info.kind));

                // Set chunk size using the specialized method
                if (!sched_info.chunk.empty() && omp_clause) {
                    OpenMPScheduleClause* sched_clause = static_cast<OpenMPScheduleClause*>(omp_clause);
                    sched_clause->setChunkSize(sched_info.chunk.c_str());
                }
                skip_std_args = true;
            } else if (clause_kind == OMPC_dist_schedule) {
                // dist_schedule clause: kind, chunk_size (similar to schedule but simpler)
                const char* args = roup_clause_arguments(roup_clause);
                OpenMPDistScheduleClauseKind dist_kind = OMPC_DIST_SCHEDULE_KIND_unknown;
                std::string chunk;

                if (args && args[0] != '\0') {
                    std::string args_str(args);
                    // Parse: static,chunk or just static
                    std::vector<std::string> parts = parseClauseArguments(args);
                    if (!parts.empty()) {
                        std::string kind_str = parts[0];
                        std::transform(kind_str.begin(), kind_str.end(), kind_str.begin(), ::tolower);
                        if (kind_str == "static") {
                            dist_kind = OMPC_DIST_SCHEDULE_KIND_static;
                        }
                        if (parts.size() > 1) {
                            chunk = parts[1];
                        }
                    }
                }

                omp_clause = dir->addOpenMPClause(static_cast<int>(clause_kind), static_cast<int>(dist_kind));
                if (!chunk.empty() && omp_clause) {
                    OpenMPDistScheduleClause* dist_clause = static_cast<OpenMPDistScheduleClause*>(omp_clause);
                    dist_clause->setChunkSize(chunk.c_str());
                }
                skip_std_args = true;
            } else if (clause_kind == OMPC_reduction) {
                // Reduction: parse modifier, operator, and variable list from arguments
                // Format: [modifier,] operator : variables
                const char* args = roup_clause_arguments(roup_clause);
                OpenMPReductionClauseModifier modifier = OMPC_REDUCTION_MODIFIER_unspecified;
                OpenMPReductionClauseIdentifier identifier = OMPC_REDUCTION_IDENTIFIER_unknown;
                std::string vars;
                std::string user_defined_identifier_str;

                if (args && args[0] != '\0') {
                    std::string args_str(args);
                    size_t colon_pos = args_str.find(':');
                    if (colon_pos != std::string::npos) {
                        std::string before_colon = args_str.substr(0, colon_pos);
                        vars = args_str.substr(colon_pos + 1);

                        // Parse modifier and operator from before colon
                        std::vector<std::string> parts = parseClauseArguments(before_colon.c_str());
                        for (const auto& part : parts) {
                            std::string p_lower = part;
                            std::transform(p_lower.begin(), p_lower.end(), p_lower.begin(), ::tolower);
                            // Check for modifiers
                            if (p_lower == "inscan") modifier = OMPC_REDUCTION_MODIFIER_inscan;
                            else if (p_lower == "task") modifier = OMPC_REDUCTION_MODIFIER_task;
                            else if (p_lower == "default") modifier = OMPC_REDUCTION_MODIFIER_default;
                            // Check for operators
                            else if (part == "+") identifier = OMPC_REDUCTION_IDENTIFIER_plus;
                            else if (part == "-") identifier = OMPC_REDUCTION_IDENTIFIER_minus;
                            else if (part == "*") identifier = OMPC_REDUCTION_IDENTIFIER_mul;
                            else if (part == "&") identifier = OMPC_REDUCTION_IDENTIFIER_bitand;
                            else if (part == "|") identifier = OMPC_REDUCTION_IDENTIFIER_bitor;
                            else if (part == "^") identifier = OMPC_REDUCTION_IDENTIFIER_bitxor;
                            else if (part == "&&") identifier = OMPC_REDUCTION_IDENTIFIER_logand;
                            else if (part == "||") identifier = OMPC_REDUCTION_IDENTIFIER_logor;
                            else if (p_lower == "max") identifier = OMPC_REDUCTION_IDENTIFIER_max;
                            else if (p_lower == "min") identifier = OMPC_REDUCTION_IDENTIFIER_min;
                            else if (identifier == OMPC_REDUCTION_IDENTIFIER_unknown) {
                                // User-defined identifier
                                identifier = OMPC_REDUCTION_IDENTIFIER_user;
                                user_defined_identifier_str = part;
                            }
                        }
                    }
                }

                // Allocate user-defined identifier if needed (ompparser takes ownership)
                char* user_defined_id_cstr = nullptr;
                if (!user_defined_identifier_str.empty()) {
                    user_defined_id_cstr = strdup(user_defined_identifier_str.c_str());
                }

                omp_clause = dir->addOpenMPClause(static_cast<int>(clause_kind),
                    static_cast<int>(modifier),
                    static_cast<int>(identifier),
                    user_defined_id_cstr);

                // Add variables
                if (!vars.empty() && omp_clause) {
                    std::vector<std::string> var_list = parseClauseArguments(vars.c_str());
                    for (const auto& v : var_list) {
                        omp_clause->addLangExpr(v.c_str());
                    }
                }
                skip_std_args = true;
            } else if (clause_kind == OMPC_proc_bind) {
                // proc_bind(master|close|spread)
                const char* args = roup_clause_arguments(roup_clause);
                OpenMPProcBindClauseKind proc_bind_kind = OMPC_PROC_BIND_unknown;
                if (args && args[0] != '\0') {
                    std::string arg_lower(args);
                    std::transform(arg_lower.begin(), arg_lower.end(), arg_lower.begin(), ::tolower);
                    if (arg_lower.find("master") != std::string::npos) proc_bind_kind = OMPC_PROC_BIND_master;
                    else if (arg_lower.find("close") != std::string::npos) proc_bind_kind = OMPC_PROC_BIND_close;
                    else if (arg_lower.find("spread") != std::string::npos) proc_bind_kind = OMPC_PROC_BIND_spread;
                }
                omp_clause = dir->addOpenMPClause(static_cast<int>(clause_kind),
                    static_cast<int>(proc_bind_kind));
                skip_std_args = true;
            } else if (clause_kind == OMPC_if) {
                // if clause: parse directive modifier (parallel, simd, cancel, etc.)
                // Format: [directive_name:] expression
                const char* args = roup_clause_arguments(roup_clause);
                OpenMPIfClauseModifier if_modifier = OMPC_IF_MODIFIER_unspecified;
                std::string expression;

                if (args && args[0] != '\0') {
                    std::string args_str(args);
                    // Check if there's a colon indicating a directive modifier
                    size_t colon_pos = args_str.find(':');
                    if (colon_pos != std::string::npos) {
                        // Extract modifier name before colon
                        std::string modifier_str = args_str.substr(0, colon_pos);
                        // Trim spaces
                        size_t first = modifier_str.find_first_not_of(" \t");
                        size_t last = modifier_str.find_last_not_of(" \t");
                        if (first != std::string::npos && last != std::string::npos) {
                            modifier_str = modifier_str.substr(first, last - first + 1);
                        }

                        std::string modifier_lower = modifier_str;
                        std::transform(modifier_lower.begin(), modifier_lower.end(), modifier_lower.begin(), ::tolower);

                        // Map to enum
                        if (modifier_lower == "parallel") if_modifier = OMPC_IF_MODIFIER_parallel;
                        else if (modifier_lower == "simd") if_modifier = OMPC_IF_MODIFIER_simd;
                        else if (modifier_lower == "task") if_modifier = OMPC_IF_MODIFIER_task;
                        else if (modifier_lower == "cancel") if_modifier = OMPC_IF_MODIFIER_cancel;
                        else if (modifier_lower == "target") if_modifier = OMPC_IF_MODIFIER_target;
                        else if (modifier_lower == "target data") if_modifier = OMPC_IF_MODIFIER_target_data;
                        else if (modifier_lower == "target enter data") if_modifier = OMPC_IF_MODIFIER_target_enter_data;
                        else if (modifier_lower == "target exit data") if_modifier = OMPC_IF_MODIFIER_target_exit_data;
                        else if (modifier_lower == "target update") if_modifier = OMPC_IF_MODIFIER_target_update;
                        else if (modifier_lower == "taskloop") if_modifier = OMPC_IF_MODIFIER_taskloop;
                        else {
                            // Unknown modifier - treat as unspecified
                            if_modifier = OMPC_IF_MODIFIER_unspecified;
                        }

                        // Extract expression after colon
                        expression = args_str.substr(colon_pos + 1);
                        // Trim leading space
                        first = expression.find_first_not_of(" \t");
                        if (first != std::string::npos) {
                            expression = expression.substr(first);
                        }
                    } else {
                        // No colon - no modifier, just expression
                        expression = args_str;
                    }
                }

                omp_clause = dir->addOpenMPClause(static_cast<int>(clause_kind), static_cast<int>(if_modifier));

                // Add the expression
                if (!expression.empty() && omp_clause) {
                    omp_clause->addLangExpr(expression.c_str());
                }
                skip_std_args = true;
            } else {
                // Standard clause creation
                omp_clause = dir->addOpenMPClause(static_cast<int>(clause_kind));
            }

            // Get clause arguments if present and add them to the clause
            // Skip for clauses that handle arguments specially
            if (!skip_std_args) {
                const char* args = roup_clause_arguments(roup_clause);
                if (args && args[0] != '\0' && omp_clause) {
                    // Parse arguments and add each one separately
                    // ompparser's expressionToString() will join them with ", "
                    std::vector<std::string> parsed_args = parseClauseArguments(args);
                    for (const auto& arg : parsed_args) {
                        // Apply appropriate spacing fix based on clause type
                        std::string fixed_arg;
                        if (clause_kind == OMPC_linear || clause_kind == OMPC_aligned) {
                            // linear/aligned: val(a,b,c):2 -> val( a, b, c) :2
                            fixed_arg = fixLinearAlignedModifierSpacing(arg);
                        } else {
                            // Other clauses: "conditional:a" -> "conditional: a"
                            fixed_arg = fixClauseArgumentSpacing(arg);
                        }
                        omp_clause->addLangExpr(fixed_arg.c_str());
                    }
                }
            }
        }
        roup_clause_iterator_free(iter);
    }

    // Free ROUP directive (we've extracted what we need)
    roup_directive_free(roup_dir);

    return dir;
}

} // extern "C"
